// 1. Encontrar los elementos
const boton = document.querySelector("#btnRegar");
const aviso = document.querySelector("#aviso");

// 2. Escuchar el clic
boton.addEventListener("click", () => {
  // 3. Cambiar lo que se ve
  aviso.textContent = "¡Tomatera regada!";
});

const lista = document.querySelector("#lista");
const plantas = ["Tomatera", "Albahaca", "Menta"];

function pintarLista() {
  let html = "";
  for (const planta of plantas) {
    html += "<li>" + planta + "</li>";
  }
  lista.innerHTML = html;   // vuelca todo de golpe
}

pintarLista(); // pintar al arrancar

